    dp[0][0] = 1; // Entry cost of (0, 0)

    // Use a priority queue to perform Dijkstra's algorithm
    // Each element in the queue is [currentCost, row, col, time]
    priority_queue<pair<long long, pair<int, int>>, vector<pair<long long, pair<int, int>>>, greater<>> pq;
    pq.push({1, {0, 0}}); // time starts at 1

    while (!pq.empty()) {
        // Extract the element with the minimum cost
        long long cost = pq.top().first;
        int row = pq.top().second.first;
        int col = pq.top().second.second;
        pq.pop();

        // If we have reached the destination, return the cost
        if (row == m - 1 && col == n - 1) {
