                int newCol = col + dc;

                // Check if the new cell is within bounds
                if (newRow >= 0 && newRow < m && newCol >= 0 && newCol < n) {
                    // Calculate the entry cost of the new cell
                    long long entryCost = (newRow + 1) * (newCol + 1);
                    long long newCost = cost + entryCost;

                    // Update the dp array if this is a better path
                    if (newCost < dp[newRow][newCol]) {
